 1	import * as React from 'react';
 2	import PageHeading from '@odf/shared/heading/page-heading';
 3	import { useCustomTranslation } from '@odf/shared/useCustomTranslationHook';
 4	import { HorizontalNav, useFlag } from '@openshift-console/dynamic-plugin-sdk';
 5	import { Helmet } from 'react-helmet';
 6	import { Text, TextContent, TextVariants } from '@patternfly/react-core';
 7	import { ADMIN_FLAG } from '../../constants';
 8	import { DRPolicyListPage } from '../drpolicy-list-page/drpolicy-list-page';
 9	import DRDashboard from '../mco-dashboard/disaster-recovery/dr-dashboard';
10	import { ProtectedApplicationsListPage } from '../protected-applications/list-page';
11	
12	const DisasterRecovery: React.FC = () => {
13	  const { t } = useCustomTranslation();
14	  const isAdmin = useFlag(ADMIN_FLAG);
15	
16	  const title = t('Disaster recovery');
17	  const pages = React.useMemo(
18	    () => [
19	      ...(isAdmin
20	        ? [
21	            {
22	              href: '',
23	              name: t('Overview'),
24	              component: DRDashboard,
25	            },
26	          ]
27	        : []),
28	      {
29	        href: isAdmin ? 'policies' : '',
30	        name: t('Policies'),
31	        component: DRPolicyListPage,
32	      },
33	      {
34	        href: 'protected-applications',
35	        name: t('Protected applications'),
36	        component: ProtectedApplicationsListPage,
37	      },
38	    ],
39	    [t, isAdmin]
40	  );
41	
42	  return (
43	    <>
44	      <Helmet>
45	        <title>{title}</title>
46	      </Helmet>
47	      <PageHeading title={title}>
48	        <TextContent>
49	          <Text component={TextVariants.small}>
50	            {t(
51	              'Configure and recover your business critical applications in event of any disaster.'
52	            )}
53	          </Text>
54	        </TextContent>
55	      </PageHeading>
56	      <HorizontalNav pages={pages} />
57	    </>
58	  );
59	};
60	
61	export default DisasterRecovery;

